/*
   компонент, для сортировки таблицы
   пропсы:
      fields - поля таблицы для выбора уровня сортировки
      sorting - функция обновления данных после сортировки
*/

const Sort = (props) => {
    const handleReset = () => {
        props.sorting([]);
    };

    const handleSubmit = (event) => {
        event.preventDefault();

        const levels = [];

        for (let i = 1; i <= 3; i++) {
            const field = event.target["field" + i].value;

            if (field !== "" && !levels.some(item => item.field === field)) {
                levels.push({
                    field: field,
                    isDesc: event.target["desc" + i].checked
                });
            }
        }

        props.sorting(levels);
    };

    const options = props.fields.map((item, index) =>
        <option key={ index } value={ item }>{ item }</option>
    );

    return (
        <form onSubmit={ handleSubmit } onReset={ handleReset } className="control-form">
            <p>
                <label>Первый уровень:</label>
                <select name="field1">
                    <option value="">Нет</option>
                    { options }
                </select>
            </p>
            <p className="checkbox-field">
                <label>По убыванию?</label>
                <input name="desc1" type="checkbox" />
            </p>
            <p>
                <label>Второй уровень:</label>
                <select name="field2">
                    <option value="">Нет</option>
                    { options }
                </select>
            </p>
            <p className="checkbox-field">
                <label>По убыванию?</label>
                <input name="desc2" type="checkbox" />
            </p>
            <p>
                <label>Третий уровень:</label>
                <select name="field3">
                    <option value="">Нет</option>
                    { options }
                </select>
            </p>
            <p className="checkbox-field">
                <label>По убыванию?</label>
                <input name="desc3" type="checkbox" />
            </p>
            <p className="form-buttons">
                <button type="submit">Сортировать</button>
                <button type="reset">Сбросить сортировку</button>
            </p>
        </form>
    )
}

export default Sort;
